/* ═══════════════════════════════════════════════════════════
   GAME TIMER — shared across pages
═══════════════════════════════════════════════════════════ */
const GameTimer = {
  _interval: null,
  _seconds: 0,
  _running: false,
  _currentParcial: 0,
  _parciales: [],
  _tiempoParcial: null,
  _countDown: false,

  init(parciales, tiempoParcial){
    this.reset();
    this._parciales = parciales || [];
    this._tiempoParcial = tiempoParcial;
    this._countDown = !!tiempoParcial;
    if(this._countDown){
      const parsed = this._parseTime(tiempoParcial);
      this._seconds = parsed;
    }
    this._currentParcial = 0;
    this._render();
  },

  _parseTime(str){
    if(!str) return 0;
    const m = str.match(/(\d+)/);
    return m ? parseInt(m[1]) * 60 : 0;
  },

  toggle(){
    if(this._running) this.pause();
    else this.play();
  },

  play(){
    if(this._running) return;
    this._running = true;
    this._interval = setInterval(() => {
      if(this._countDown){
        this._seconds--;
        if(this._seconds <= 0){ this._seconds = 0; this.pause(); }
      } else {
        this._seconds++;
      }
      this._render();
    }, 1000);
    this._updateBtn();
  },

  pause(){
    this._running = false;
    clearInterval(this._interval);
    this._updateBtn();
  },

  reset(){
    this.pause();
    this._seconds = 0;
    if(this._countDown && this._tiempoParcial){
      this._seconds = this._parseTime(this._tiempoParcial);
    }
    this._render();
  },

  nextParcial(){
    if(this._currentParcial < this._parciales.length - 1){
      this._currentParcial++;
      this.reset();
      this._render();
    }
  },

  prevParcial(){
    if(this._currentParcial > 0){
      this._currentParcial--;
      this.reset();
      this._render();
    }
  },

  _formatTime(s){
    const mm = String(Math.floor(s / 60)).padStart(2,'0');
    const ss = String(s % 60).padStart(2,'0');
    return `${mm}:${ss}`;
  },

  _render(){
    const el = document.getElementById('gameTimerDisplay');
    if(el) el.textContent = this._formatTime(this._seconds);
    const lbl = document.getElementById('gameTimerParcial');
    if(lbl && this._parciales.length > 0){
      lbl.textContent = this._parciales[this._currentParcial] || '';
    }
  },

  _updateBtn(){
    const btn = document.getElementById('gameTimerBtn');
    if(!btn) return;
    btn.textContent = this._running ? '⏸ Pausar' : '▶ Iniciar';
    btn.className = this._running ? 'timer-btn pause' : 'timer-btn play';
  },

  buildHTML(parciales, tiempoParcial){
    if(!parciales || parciales.length === 0) return '';
    return `<div class="game-timer">
      <div class="timer-parcial-nav">
        <button class="timer-nav-btn" onclick="GameTimer.prevParcial()">‹</button>
        <span class="timer-parcial-label" id="gameTimerParcial">${parciales[0]}</span>
        <button class="timer-nav-btn" onclick="GameTimer.nextParcial()">›</button>
      </div>
      <div class="timer-display" id="gameTimerDisplay">${tiempoParcial ? this._formatTime(this._parseTime(tiempoParcial)) : '00:00'}</div>
      <div class="timer-controls">
        <button class="timer-btn play" id="gameTimerBtn" onclick="GameTimer.toggle()">▶ Iniciar</button>
        <button class="timer-btn reset" onclick="GameTimer.reset()">↺ Reset</button>
      </div>
      ${tiempoParcial ? `<div class="timer-info">Duración: ${tiempoParcial}</div>` : ''}
    </div>`;
  }
};

/* ═══════════════════════════════════════════════════════════
   INPUT VALIDATION — shared across pages
═══════════════════════════════════════════════════════════ */
const InputValidation = {
  /* Only allow digits in score inputs */
  numericOnly(e){
    const inp = e.target;
    inp.value = inp.value.replace(/[^\d]/g, '');
  },

  /* Time mask: auto-format as mm:ss or hh:mm:ss */
  timeMask(e){
    const inp = e.target;
    let raw = inp.value.replace(/[^\d]/g, '');
    if(raw.length > 6) raw = raw.substring(0,6);
    if(raw.length <= 2){
      inp.value = raw;
    } else if(raw.length <= 4){
      inp.value = raw.substring(0, raw.length-2) + ':' + raw.substring(raw.length-2);
    } else {
      inp.value = raw.substring(0,2) + ':' + raw.substring(2,4) + '.' + raw.substring(4);
    }
  },

  /* Decimal for judge scores: allow digits and one dot */
  decimalOnly(e){
    const inp = e.target;
    let val = inp.value.replace(/[^\d.]/g, '');
    const parts = val.split('.');
    if(parts.length > 2) val = parts[0] + '.' + parts.slice(1).join('');
    if(parseFloat(val) > 10) val = '10.00';
    inp.value = val;
  },

  /* Attach validation to all score inputs in the modal */
  attachAll(){
    document.querySelectorAll('.score-input[type="number"]').forEach(inp => {
      inp.addEventListener('input', InputValidation.numericOnly);
      inp.setAttribute('inputmode', 'numeric');
      inp.setAttribute('pattern', '[0-9]*');
    });
    document.querySelectorAll('.score-input.time').forEach(inp => {
      inp.removeAttribute('type');
      inp.setAttribute('inputmode', 'numeric');
      inp.addEventListener('input', InputValidation.timeMask);
      inp.setAttribute('placeholder', 'mm:ss');
    });
    document.querySelectorAll('.score-input[step="0.01"]').forEach(inp => {
      inp.addEventListener('input', InputValidation.decimalOnly);
      inp.setAttribute('inputmode', 'decimal');
    });
  }
};